		Join join = assertInstanceOf(Join.class, extension.getArg());
		assertTrue(containsBindingSetAssignmentFor(join.getLeftArg(), "u"));
		if (expectOptNameAssignment) {
			assertTrue(containsBindingSetAssignmentFor(join.getLeftArg(), "optName"));
		}
		if (expectOptNamePattern) {
			assertTrue(containsStatementPatternWithObject(join.getLeftArg(), "optName"));
		}
